.darma-loader-uiverse-hologram-ring-lift {
  position: relative;
  width: 180px;
  height: 150px;
  display: flex;
  justify-content: center;
  align-items: center;
  perspective: 800px;
}
.darma-loader-uiverse-hologram-ring-lift__item {
  position: absolute;
  background-color: transparent;
  width: calc(var(--i) * 7px);
  aspect-ratio: 1;
  border-radius: 50%;
  border: 3px solid var(--loader-color, #00c8ff);
  transform-style: preserve-3d;
  transform: rotateX(70deg) translateZ(25px);
  animation: darma-loader-uiverse-hologram-ring-lift-holoLift 3s ease-in-out calc(var(--i) * .08s) infinite;
  box-shadow: 0 0 15px var(--loader-secondary-color, #7cdcff), inset 0 0 15px var(--loader-secondary-color, #7cdcff);
}
@keyframes darma-loader-uiverse-hologram-ring-lift-holoLift {
  0%, 100% { transform: rotateX(70deg) translateZ(25px) translateY(0); filter: hue-rotate(0deg); }
  50% { transform: rotateX(70deg) translateZ(25px) translateY(-80px); filter: hue-rotate(180deg); }
}

